// Parse LinkedIn guest API response
const html = $input.first().json.body || '';
const jobs = [];
const regex = /<a[^>]*class="[^"]*base-card__full-link[^"]*"[^>]*href="([^"]+)"[^>]*>[\s\S]*?<span[^>]*class="[^"]*sr-only[^"]*">([^<]+)<\/span>[\s\S]*?<h4[^>]*class="[^"]*base-search-card__subtitle[^"]*"[^>]*>\s*<a[^>]*>([^<]+)<\/a>[\s\S]*?<span[^>]*class="[^"]*job-search-card__location[^"]*">([^<]+)<\/span>/gi;
let m;
while ((m = regex.exec(html)) !== null) {
  const url = m[1].split('?')[0];
  const title = m[2].trim();
  const company = m[3].trim();
  const location = m[4].trim();
  if (title && company) {
    jobs.push({title, company, location, source: 'LinkedIn', source_url: url, country: '', salary: '', notes: 'Scraped from LinkedIn'});
  }
}
return jobs.map(j => ({json: j}));

// Parse Indeed HTML response
const html = $input.first().json.body || '';
const jobs = [];
const titleRegex = /<h2[^>]*class="[^"]*jobTitle[^"]*"[^>]*>[\s\S]*?<span[^>]*>([^<]+)<\/span>/gi;
const companyRegex = /<span[^>]*data-testid="company-name"[^>]*>([^<]+)<\/span>/gi;
const locationRegex = /<div[^>]*data-testid="text-location"[^>]*>([^<]+)<\/div>/gi;
const titles = [...html.matchAll(/<span[^>]*id="jobTitle-[^"]*"[^>]*>([^<]+)<\/span>/gi)].map(m => m[1].trim());
const companies = [...html.matchAll(/<span[^>]*data-testid="company-name"[^>]*>([^<]+)<\/span>/gi)].map(m => m[1].trim());
const locations = [...html.matchAll(/<div[^>]*data-testid="text-location"[^>]*>([^<]+)<\/div>/gi)].map(m => m[1].trim());
for (let i = 0; i < titles.length; i++) {
  jobs.push({title: titles[i], company: companies[i]||'', location: locations[i]||'', source: 'Indeed', source_url: 'https://www.indeed.com', country: '', salary: '', notes: 'Scraped from Indeed'});
}
return jobs.map(j => ({json: j}));

// Parse Silent Professionals HTML
const html = $input.first().json.body || '';
const jobs = [];
const regex = /<a[^>]*href="(https:\/\/silentprofessionals\.org\/jobs\/[^"]+)"[^>]*class="[^"]*job_listing-clickbox[^"]*"[^>]*>[\s\S]*?<\/a>|<h3[^>]*>([^<]+)<\/h3>/gi;
// Simpler approach: find job titles and links
const titleMatches = [...html.matchAll(/<a[^>]*href="(https:\/\/silentprofessionals\.org\/jobs\/[^"]+)"[^>]*>\s*([^<]+)\s*<\/a>/gi)];
for (const m of titleMatches) {
  const url = m[1];
  const title = m[2].trim();
  if (title && title.length > 5 && !title.includes('Silent') && !title.includes('Home')) {
    jobs.push({title, company: 'Silent Professionals', location: '', source: 'Silent Professionals', source_url: url, country: '', salary: '', notes: 'Scraped from Silent Professionals'});
  }
}
return jobs.slice(0, 20).map(j => ({json: j}));

// Deduplicate and clean
const seen = new Set();
const clean = [];
for (const item of $input.all()) {
  const j = item.json;
  const key = (j.title + '|' + j.company + '|' + j.source).toLowerCase();
  if (!seen.has(key) && j.title) {
    seen.add(key);
    // Determine country from location
    let country = '';
    const loc = (j.location || '').toLowerCase();
    if (loc.includes(', uk') || loc.includes('london') || loc.includes('surrey')) country = 'UK';
    else if (loc.includes('dubai') || loc.includes('uae') || loc.includes('abu dhabi')) country = 'UAE';
    else if (/\b[A-Z]{2}\b/.test(j.location) || loc.includes('usa') || loc.includes('united states')) country = 'USA';
    clean.push({json: {...j, country: country || j.country || ''}});
  }
}
return clean;
